// Valida e normaliza o payload do widget de chat
const body = $input.first().json.body;

const required = ['visitor_id', 'text'];
for (const field of required) {
  if (!body[field]) {
    throw new Error(`Campo obrigatório ausente: ${field}`);
  }
}

if (body.text.length > 4096) {
  throw new Error('Mensagem muito longa');
}

return [{
  json: {
    external_user_id: body.visitor_id,
    channel: 'website',
    text: body.text.trim(),
    user_name: body.name || null,
    user_email: body.email || null,
    metadata: {
      page_url: body.page_url || null,
      user_agent: body.user_agent || null,
      session_id: body.session_id || null
    }
  }
}];

// Resposta normal do bot — retorna JSON ao widget
const data = $input.first().json;
return [{
  json: {
    ok: true,
    conversation_id: data.conversation_id,
    message_id: data.message_id,
    reply: data.reply,
    intent: data.intent,
    human_handoff: false,
    tokens_used: data.tokens_used
  }
}];

// Resposta de handoff — widget exibe banner de transferência
const data = $input.first().json;
return [{
  json: {
    ok: true,
    conversation_id: data.conversation_id,
    message_id: data.message_id,
    reply: data.reply,
    intent: data.intent,
    human_handoff: true,
    handoff_message: 'Um agente humano irá continuar seu atendimento em breve. Por favor, aguarde.',
    tokens_used: data.tokens_used
  }
}];

// Notifica equipe sobre handoff via website
// Substitua pelo nó Slack, Email, ou Zendesk conforme seu stack
const data = $('Chama Backend Python').first().json;
console.log('HANDOFF WEBSITE', JSON.stringify({
  conversation_id: data.conversation_id,
  intent: data.intent,
  urgency_score: data.urgency_score,
  ts: new Date().toISOString()
}));

